const data = $input.first().json;
const channel = data.rss?.channel || {};
const rawItems = channel.item || [];
const itemArray = Array.isArray(rawItems) ? rawItems : [rawItems];

const twoHoursAgo = Date.now() - 2 * 60 * 60 * 1000;

const recent = itemArray.filter(item => {
  const rawDate = item.pubDate || '';
  const ts = new Date(rawDate).getTime();
  return !isNaN(ts) && ts >= twoHoursAgo;
});

const headlines = recent.slice(0, 8).map((item, i) => {
  const title = (item.title || '').replace(/<[^>]+>/g, '').trim();
  return `${i + 1}. ${title}`;
}).join('\n');

const groqPayload = {
  model: 'llama-3.3-70b-versatile',
  messages: [
    {
      role: 'system',
      content: 'You are a B2B social media content expert. Write insight-driven posts that establish thought leadership. Write exactly 3 punchy sentences followed by 2-3 relevant hashtags. Be direct, urgent, and share-worthy.'
    },
    {
      role: 'user',
      content: `These AI marketing headlines are trending right now:\n\n${headlines}\n\nWrite one compelling 3-sentence social media post that a marketing agency would be proud to share. Make it feel urgent and insightful.`
    }
  ],
  temperature: 0.8,
  max_tokens: 300
};

return [{
  json: {
    recentCount: recent.length,
    headlines,
    groqPayload,
    checkedAt: new Date().toISOString()
  }
}];

const groqResponse = $input.first().json;
const generatedPost = groqResponse.choices?.[0]?.message?.content || 'Content generation failed — check Groq API key.';

const filterData = $('Filter Recent Articles').first().json;
const recentCount = filterData.recentCount;
const checkedAt = filterData.checkedAt;

const timestamp = new Date(checkedAt).toLocaleString('en-GB', {
  timeZone: 'UTC',
  day: '2-digit',
  month: 'short',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
}) + ' UTC';

return [{
  json: {
    username: 'Trend Engine',
    embeds: [{
      title: '\uD83D\uDFE2 Trend Detected: AI Marketing',
      description: generatedPost,
      color: 5763719,
      fields: [
        {
          name: '\uD83D\uDCF0 Articles in Last 2h',
          value: `${recentCount} articles trending`,
          inline: true
        },
        {
          name: '\u23F0 Detected At',
          value: timestamp,
          inline: true
        },
        {
          name: '\uD83E\uDD16 AI Model',
          value: 'Groq \u00B7 llama-3.3-70b-versatile',
          inline: true
        }
      ],
      footer: {
        text: 'Live Trend-to-Content Engine \u00B7 n8n + Groq AI'
      }
    }]
  }
}];
